values ('Lớp 11 – Kiểm tra thường xuyên Tuần 3 (Dao động điều hòa)', 40, true, $json$[{"type": "multiple_choice", "question": "Trong dao động điều hoà thì li độ, vận tốc và gia tốc là những đại lượng biến đổi theo hàm sin hoặc cosin theo thời gian và", "options": ["cùng biên độ.", "cùng pha ban đầu.", "cùng chu kỳ.", "cùng pha dao động."], "answer": 2, "explanation": "Li độ, vận tốc và gia tốc là những đại lượng biến đổi theo hàm sin hoặc cosin theo thời gian và cùng tần số góc <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image1_rId10001.png\" alt=\"\" style=\"height:16px\"> cùng chu kỳ."}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa. Li độ đạt giá trị cực đại khi vật qua vị trí", "options": ["biên âm.", "biên dương.", "Biên.", "cân bằng."], "answer": 1, "explanation": "Khi ở vị trí biên dương thì li độ cực đại <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image2_rId10003.png\" alt=\"\" style=\"height:19px\">"}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa. Li độ đạt giá trị cực tiểu khi vật qua vị trí", "options": ["biên âm.", "biên dương.", "Biên.", "cân bằng."], "answer": 0, "explanation": "Khi ở vị trí biên âm thì li độ có giá trị cực tiểu <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image3_rId10005.png\" alt=\"\" style=\"height:19px\">"}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa. Vật cách xa vị trí cần bằng nhất khi vật qua vị trí", "options": ["biên âm.", "biên dương.", "biên.", "cân bằng."], "answer": 2, "explanation": "Vật cách xa vị trí cần bằng nhất khi vật qua vị trí biên <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image4_rId10007.png\" alt=\"\" style=\"height:27px\">"}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa. Vận tốc đạt giá trị cực đại khi vật qua vị trí", "options": ["biên.", "cân bằng.", "cân bằng theo chiều dương.", "cân bằng theo chiều âm."], "answer": 2, "explanation": "Vận tốc đạt giá trị cực đại khi vật qua vị trí cân bằng theo chiều dương <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image5_rId10009.png\" alt=\"\" style=\"height:25px\">"}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa.Vận tốc đạt giá trị cực tiểu khi vật qua vị trí", "options": ["biên.", "cân bằng.", "cân bằng theo chiều dương.", "cân bằng theo chiều âm."], "answer": 3, "explanation": "Vận tốc đạt giá trị cực tiểu khi vật qua vị trí cân bằng theo chiều âm <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image6_rId10011.png\" alt=\"\" style=\"height:25px\">"}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa. Tốc độ đạt giá trị cực đại khi vật qua vị trí", "options": ["biên.", "cân bằng.", "cân bằng theo chiều dương.", "cân bằng theo chiều âm."], "answer": 1, "explanation": "Tốc độ đạt giá trị cực đại khi vật qua vị trí cân bằng <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image7_rId10013.png\" alt=\"\" style=\"height:27px\">"}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa. Tốc độ đạt giá trị cực tiểu khi vật qua vị trí", "options": ["biên.", "cân bằng.", "cân bằng theo chiều dương.", "cân bằng theo chiều âm."], "answer": 0, "explanation": "Tốc độ đạt giá trị cực tiểu khi vật qua vị trí biên <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image8_rId10015.png\" alt=\"\" style=\"height:19px\">"}, {"type": "multiple_choice", "question": "Trong dao động điều hòa, gia tốc của vật đạt giá trị cực đại khi vật qua vị trí", "options": ["biên âm.", "biên dương.", "biên.", "cân bằng."], "answer": 0, "explanation": "Trong dao động điều hòa, gia tốc của vật đạt giá trị cực đại khi vật qua vị trí biên âm."}, {"type": "multiple_choice", "question": "Trong dao động điều hòa, gia tốc đạt giá trị cực tiểu khi vật qua vị trí", "options": ["biên âm.", "biên dương.", "biên.", "cân bằng."], "answer": 1, "explanation": "Trong dao động điều hòa, gia tốc của vật đạt giá trị cực tiểu khi vật qua vị trí biên dương."}, {"type": "multiple_choice", "question": "Cho vật dao động điều hòa. Gia tốc có giá trị bằng 0 khi vật qua vị trí", "options": ["biên âm.", "biên dương.", "biên.", "cân bằng."], "answer": 3, "explanation": "Vì <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image10_rId10017.png\" alt=\"\" style=\"height:21px\"> nên gia tốc của vật dao động điều hòa có giá trị bằng 0 khi vật qua vị trí cân bằng."}, {"type": "multiple_choice", "question": "Khi một vật dao động điều hòa, chuyển động của vật từ vị trí biên về vị trí cân bằng là chuyển động", "options": ["nhanh dần đều.", "chậm dần đều.", "nhanh dần.", "chậm dần."], "answer": 2, "explanation": "Khi một vật dao động điều hòa, chuyển động của vật từ vị trí biên về vị trí cân bằng là chuyển động nhanh dần."}, {"type": "multiple_choice", "question": "Khi một vật dao động điều hòa, chuyển động của vật từ vị trí cân bằng ra vị trí biên dương là chuyển động", "options": ["nhanh dần đều.", "chậm dần đều.", "nhanh dần.", "chậm dần."], "answer": 3, "explanation": "Khi một vật dao động điều hòa, chuyển động của vật từ vị trí cân bằng ra vị trí biên dương là chuyển động chậm dần."}, {"type": "multiple_choice", "question": "Khi một vật dao động điều hòa, chuyển động của vật từ vị trí cân bằng ra vị trí biên âm là chuyển động", "options": ["nhanh dần đều.", "chậm dần đều.", "nhanh dần.", "chậm dần."], "answer": 3, "explanation": "Khi một vật dao động điều hòa, chuyển động của vật từ vị trí cân bằng ra vị trí biên âm là chuyển động chậm dần."}, {"type": "multiple_choice", "question": "Một vật dao động điều hòa. Khi vật đi từ vị trí biên dương đến biên âm thì li độ của vật", "options": ["giảm rồi tăng.", "tăng rồi giảm.", "giảm.", "tăng."], "answer": 2, "explanation": "Khi vật đi từ vị trí biên dương đến biên âm thì li độ của vật giảm."}, {"type": "multiple_choice", "question": "Một vật dao động điều hòa. Khi vật đi từ vị trí biên âm đến biên dương thì gia tốc của vật", "options": ["giảm rồi tăng.", "tăng rồi giảm.", "giảm.", "tăng."], "answer": 2, "explanation": "Khi vật đi từ vị trí biên âm đến biên dương thì gia tốc của vật giảm."}, {"type": "multiple_choice", "question": "Một vật dao động điều hòa. Khi vật đi từ vị trí biên dương đến biên âm thì gia tốc của vật", "options": ["giảm rồi tăng.", "tăng rồi giảm.", "giảm.", "tăng."], "answer": 3, "explanation": "Khi vật đi từ vị trí biên dương đến biên âm thì gia tốc của vật tăng."}, {"type": "multiple_choice", "question": "Trong dao động điều hoà, li độ biến đổi", "options": ["cùng pha với vận tốc.", "trễ pha 90^0^ so với vận tốc.", "vuông pha với gia tốc.", "cùng pha với gia tốc."], "answer": 1, "explanation": "Ta có Trong dao động điều hòa thì vân tốc sớm pha hơn li độ <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image12_rId10019.png\" alt=\"\" style=\"height:42px\"> và trễ pha <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image13_rId10021.png\" alt=\"\" style=\"height:42px\"> so với gia tốc."}, {"type": "multiple_choice", "question": "Trong dao động điều hoà, vận tốc biến đổi", "options": ["ngược pha với gia tốc.", "cùng pha với Li độ.", "ngược pha với gia tốc.", "sớm pha 90^0^ so với Li độ."], "answer": 3, "explanation": "Trong dao động điều hoà,vận tốc biến đổi sớm pha 90^0^ so với Li độ."}, {"type": "multiple_choice", "question": "Trong dao động điều hoà, gia tốc biến đổi", "options": ["cùng pha với vận tốc.", "sớm pha 90^0^ so với vận tốc.", "ngược pha với vận tốc.", "trễ pha 90^0^ so với vận tốc."], "answer": 1, "explanation": "Trong dao động điều hoà, gia tốc biến đổi sớm pha 90^0^ so với vận tốc."}, {"type": "multiple_choice", "question": "Đồ thị quan hệ giữa li độ, vận tốc, gia tốc với thời gian là đường", "options": ["thẳng.", "elip.", "parabol.", "hình sin."], "answer": 3, "explanation": "Trong dao động điều hòa đồ thị quan hệ giữa Li độ, vận tốc, gia tốc đối với thời gian là đường hình sin."}, {"type": "multiple_choice", "question": "Đồ thị quan hệ giữa li độ và vận tốc là đường", "options": ["thẳng.", "elip.", "parabol.", "hình sin."], "answer": 1, "explanation": "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image14_rId10023.png\" alt=\"\" style=\"height:14px\"> và <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image15_rId10025.png\" alt=\"\" style=\"height:14px\"> vuông pha <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image16_rId10027.png\" alt=\"\" style=\"height:48px\"> đồ thị là đường elip."}, {"type": "multiple_choice", "question": "Đồ thị quan hệ giữa vận tốc và gia tốc là đường", "options": ["thẳng.", "elip.", "parabol.", "hình sin."], "answer": 1, "explanation": "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image17_rId10029.png\" alt=\"\" style=\"height:14px\"> và <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image18_rId10031.png\" alt=\"\" style=\"height:14px\"> vuông pha <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image19_rId10033.png\" alt=\"\" style=\"height:48px\"> đồ thị là đường elip."}, {"type": "multiple_choice", "question": "Đồ thị quan hệ giữa li độ và gia tốc là", "options": ["đoạn thẳng qua gốc tọa độ", "đường hình sin", "đường elip", "đường thẳng qua gốc tọa độ"], "answer": 0, "explanation": "Mối liên hệ giữa li độ và gia tốc <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image20_rId10035.png\" alt=\"\" style=\"height:21px\">đồ thị là đoạn thẳng qua gốc tọa độ."}, {"type": "multiple_choice", "question": "Một vật dao động điều hòa có phương trình <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image21_rId10037.png\" alt=\"\" style=\"height:27px\"> Gọi v và a lần lượt là vận tốc và gia tốc của vật. Hệ thức đúng là", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image22_rId10039.png\" alt=\"\" style=\"height:44px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image23_rId10041.png\" alt=\"\" style=\"height:44px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image24_rId10043.png\" alt=\"\" style=\"height:44px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image25_rId10045.png\" alt=\"\" style=\"height:44px\">"], "answer": 2, "explanation": "Mối quan hệ không phụ thuộc vào thời gian giữa v và a là <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image26_rId10047.png\" alt=\"\" style=\"height:44px\">"}, {"type": "multiple_choice", "question": "Một vật dao động điều hòa với biên độ <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image27_rId10049.png\" alt=\"\" style=\"height:16px\"> và tốc độ cực đại <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image28_rId10051.png\" alt=\"\" style=\"height:25px\"> Tần số góc của vật dao động là", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image29_rId10053.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image30_rId10055.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image31_rId10057.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image32_rId10059.png\" alt=\"\" style=\"height:42px\">"], "answer": 0, "explanation": "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image33_rId10061.png\" alt=\"\" style=\"height:42px\">"}, {"type": "multiple_choice", "question": "Khi một vật dao động điều hòa, chuyển động của vật từ vị trí biên về vị trí cân bằng là chuyển động", "options": ["nhanh dần đều.", "chậm dần đều.", "nhanh dần.", "chậm dần."], "answer": 2, "explanation": "Vật từ vị trí biên về vị trí cân bằng thì gia tốc và vận tốc cùng hướng nên chuyển động nhanh dần"}, {"type": "multiple_choice", "question": "Một chất điểm dao động điều hòa trên trục Ox. Vectơ gia tốc của chất điểm có &gt;", "options": ["độ lớn cực đại ở vị trí biên, chiều luôn hướng ra biên. &gt; &gt;", "độ lớn cực tiểu khi qua vị trí cân bằng luôn cùng chiều với &gt; vectơ vận tốc. &gt; &gt;", "độ lớn không đổi, chiều luôn hướng về vị trí cân bằng. &gt; &gt;", "độ lớn tỉ lệ với độ lớn của li độ, chiều luôn hướng về vị trí &gt; cân bằng."], "answer": 3, "explanation": "Một chất điểm dao động điều hòa trên trục Ox. Vectơ gia tốc của chất điểm có độ lớn tỉ lệ với độ lớn của li độ, chiều luôn hướng về vị trí cân bằng"}, {"type": "multiple_choice", "question": "Một vật dao động điều hòa với biên độ <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image34_rId10063.png\" alt=\"\" style=\"height:16px\"> và tốc độ cực đại <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image35_rId10065.png\" alt=\"\" style=\"height:19px\">. Tần số góc của vật dao động là", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image36_rId10067.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image37_rId10069.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image38_rId10071.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image39_rId10073.png\" alt=\"\" style=\"height:42px\">"], "answer": 2, "explanation": "Ta có công thức của tốc độ cực đại là <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image40_rId10075.png\" alt=\"\" style=\"height:42px\">"}, {"type": "multiple_choice", "question": "Một vật dao động điều hòa với biên độ A và tốc độ cực đại <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image41_rId10077.png\" alt=\"\" style=\"height:25px\"> Chu kỳ dao động của vật là", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image42_rId10079.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image43_rId10081.png\" alt=\"\" style=\"height:45px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image44_rId10083.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image45_rId10085.png\" alt=\"\" style=\"height:45px\">"], "answer": 3, "explanation": "Ta có công thức của tốc độ cực đại là <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image46_rId10087.png\" alt=\"\" style=\"height:45px\">"}, {"type": "multiple_choice", "question": "Một vật thực hiện dao động điều hoà với chu kỳ dao động <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image47_rId10089.png\" alt=\"\" style=\"height:21px\"> và biên độ dao động <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image48_rId10091.png\" alt=\"\" style=\"height:19px\"> Tại thời điểm vật đi qua vị trí cân bằng, vận tốc của vật đó bằng", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image49_rId10093.png\" alt=\"\" style=\"height:21px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image50_rId10095.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image51_rId10097.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image52_rId10099.png\" alt=\"\" style=\"height:19px\">"], "answer": 2, "explanation": "Độ lớn vận tốc khi qua vị trí cân bằng <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image53_rId10101.png\" alt=\"\" style=\"height:42px\">"}, {"type": "multiple_choice", "question": "Phương trình li độ của một vật dao động điều hoà có dạng <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image68_rId10103.png\" alt=\"\" style=\"height:27px\"> Phương trình vận tốc của vật là", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image69_rId10105.png\" alt=\"\" style=\"height:27px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image70_rId10107.png\" alt=\"\" style=\"height:27px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image71_rId10109.png\" alt=\"\" style=\"height:27px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image72_rId10111.png\" alt=\"\" style=\"height:27px\">"], "answer": 3, "explanation": "Ta có vận tốc <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image73_rId10113.png\" alt=\"\" style=\"height:45px\">"}, {"type": "multiple_choice", "question": "Phương trình li độ của một vật dao động điều hoà có dạng <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image74_rId10115.png