/media/image88_rId10143.png\" alt=\"\" style=\"height:48px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image89_rId10145.png\" alt=\"\" style=\"height:48px\">"], "answer": 1, "explanation": "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image90_rId10147.png\" alt=\"\" style=\"height:14px\"> và <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image91_rId10149.png\" alt=\"\" style=\"height:14px\"> vuông pha <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image92_rId10151.png\" alt=\"\" style=\"height:48px\">"}, {"type": "multiple_choice", "question": "Thời gian ngắn nhất vật đi từ vị trí cân bằng đến biên là", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image93_rId10153.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image94_rId10155.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image95_rId10157.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image96_rId10159.png\" alt=\"\" style=\"height:42px\">"], "answer": 0, "explanation": "Thời gian ngắn nhất vật đi từ vị trí cân bằng đến biên là <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image97_rId10161.png\" alt=\"\" style=\"height:42px\">"}, {"type": "multiple_choice", "question": "Thời gian ngắn nhất vật đi từ vị trí cân bằng đến vị trí có li độ <img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image98_rId10163.png\" alt=\"\" style=\"height:42px\"> là", "options": ["<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image99_rId10165.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image100_rId10167.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image101_rId10169.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/11-kttx-tuan-3/media/image102_rId10171.png\" alt=\"\" style=\"height:42px\">"], "answer": 3, "explanation": "Thời