insert into public.exams (title, duration_minutes, published, questions)
values ('Kiểm tra thường xuyên – Điện trường', 20, true, $json$[{"type": "multiple_choice", "question": "Những đường sức điện của điện trường xung quanh một điện tích điểm<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image1_rId10001.png\" alt=\"\" style=\"height:21px\">có dạng là những", "options": ["đường cong và đường thẳng có chiều đi vào điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image2_rId10003.png\" alt=\"\" style=\"height:21px\">", "đường thẳng có chiều đi vào điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image3_rId10005.png\" alt=\"\" style=\"height:21px\">", "đường cong và đường thẳng có chiều đi ra khỏi điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image4_rId10007.png\" alt=\"\" style=\"height:21px\">", "đường thẳng có chiều đi ra khỏi điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image5_rId10009.png\" alt=\"\" style=\"height:21px\">"], "answer": 1, "explanation": ""}, {"type": "multiple_choice", "question": "Cường độ điện trường tại một điểm đặc trưng cho điện trường tại điểm đó về", "options": ["phương của vector cường độ điện trường.", "chiều của vector cường độ điện trường.", "phương diện tác dụng lực.", "độ lớn của lực điện."], "answer": 2, "explanation": ""}, {"type": "multiple_choice", "question": "Điện trường được tạo ra bởi điện tích, là dạng vật chất tồn tại quanh điện tích và", "options": ["tác dụng lực lên mọi vật đặt trong nó.", "tác dụng lực điện lên mọi vật đặt trong nó.", "truyền lực cho các điện tích.", "truyền tương tác giữa các điện tích."], "answer": 3, "explanation": ""}, {"type": "multiple_choice", "question": "Đơn vị của cường độ điện trường là", "options": ["<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image6_rId10011.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image7_rId10013.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image8_rId10015.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image9_rId10017.png\" alt=\"\" style=\"height:19px\">"], "answer": 2, "explanation": ""}, {"type": "multiple_choice", "question": "Đại lượng nào dưới đây không liên quan tới cường độ điện trường của một điện tích điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image10_rId10019.png\" alt=\"\" style=\"height:21px\"> đặt tại một điểm trong chân không?", "options": ["Khoảng cách r từ <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image11_rId10021.png\" alt=\"\" style=\"height:21px\"> đến điểm quan sát.", "Hằng số điện của chân không.", "Độ lớn của điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image12_rId10023.png\" alt=\"\" style=\"height:21px\">", "Độ lớn của điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image13_rId10025.png\" alt=\"\" style=\"height:21px\"> đặt tại điểm quan sát."], "answer": 3, "explanation": ""}, {"type": "multiple_choice", "question": "Cường độ điện trường tại một điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image14_rId10027.png\" alt=\"\" style=\"height:17px\">trong điện trường bất kì là đại lượng", "options": ["vector, có phương, chiều và độ lớn phụ thuộc vào vị trí của điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image15_rId10029.png\" alt=\"\" style=\"height:19px\">", "vector, chỉ có độ lớn phụ thuộc vào vị trí của điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image16_rId10031.png\" alt=\"\" style=\"height:19px\">", "vô hướng, có giá trị luôn dương.", "vô hướng, có thể có giá trị âm hoặc dương."], "answer": 0, "explanation": ""}, {"type": "multiple_choice", "question": "Đường sức điện cho chúng ta biết về", "options": ["độ lớn của cường độ điện trường của các điểm trên đường sức điện.", "phương và chiều của cường độ điện trường tại mỗi điểm trên đường sức điện.", "độ lớn của lực điện tác dụng lên điện tích thử <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image17_rId10033.png\" alt=\"\" style=\"height:17px\">", "độ mạnh yếu của điện trường."], "answer": 1, "explanation": ""}, {"type": "multiple_choice", "question": "Đơn vị của cường độ điện trường là", "options": ["<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image18_rId10035.png\" alt=\"\" style=\"height:21px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image19_rId10037.png\" alt=\"\" style=\"height:21px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image20_rId10039.png\" alt=\"\" style=\"height:21px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image21_rId10041.png\" alt=\"\" style=\"height:21px\">"], "answer": 2, "explanation": ""}, {"type": "multiple_choice", "question": "Giả sử đặt một electron và một proton riêng biệt trong một điện trường và hai điện trường này giống hệt nhau. Phát biểu nào sau đây là đúng?", "options": ["Electron và proton chịu tác dụng của cùng một lực điện.", "Lực điện tác dụng lên proton có độ lớn lớn hơn lực điện tác dụng lên electron nhưng ngược hướng.", "Lực điện tác dụng lên proton có độ lớn bằng lực điện tác dụng lên electron nhưng ngược hướng.", "Electron và proton có cùng gia tốc."], "answer": 2, "explanation": ""}, {"type": "multiple_choice", "question": "Sắp xếp độ lớn cường độ điện trường tại các điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image36_rId10043.png\" alt=\"\" style=\"height:21px\"> <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image37_rId10045.png\" alt=\"\" style=\"height:17px\"> và <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image38_rId10047.png\" alt=\"\" style=\"height:19px\"> trong hình bên theo thứ tự giảm dần từ lớn nhất đến nhỏ nhất. <img class=\"figure\" src=\"/exams/kttx-dien-truong/media/image10049.png\" alt=\"\">", "options": ["<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image39_rId10052.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image40_rId10054.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image41_rId10056.png\" alt=\"\" style=\"height:19px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image42_rId10058.png\" alt=\"\" style=\"height:19px\">"], "answer": 0, "explanation": ""}, {"type": "multiple_choice", "question": "Công thức tính độ lớn cường độ điện trường của điện tích điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image44_rId10060.png\" alt=\"\" style=\"height:21px\"> đặt trong chân không là", "options": ["<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image45_rId10062.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image46_rId10064.png\" alt=\"\" style=\"height:44px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image47_rId10066.png\" alt=\"\" style=\"height:44px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image48_rId10068.png\" alt=\"\" style=\"height:42px\">"], "answer": 1, "explanation": ""}, {"type": "multiple_choice", "question": "Cường độ điện trường của một điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image49_rId10070.png\" alt=\"\" style=\"height:21px\"> gây ra tại một điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image50_rId10072.png\" alt=\"\" style=\"height:17px\"> không phụ thuộc vào", "options": ["điện tích thử <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image51_rId10074.png\" alt=\"\" style=\"height:17px\">", "hằng số điện môi của môi trường.", "điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image52_rId10076.png\" alt=\"\" style=\"height:21px\">", "khoảng cách từ điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image53_rId10078.png\" alt=\"\" style=\"height:17px\"> đến điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image54_rId10080.png\" alt=\"\" style=\"height:21px\">"], "answer": 0, "explanation": ""}, {"type": "multiple_choice", "question": "Phát biểu nào sau đây không đúng khi nói về điện trường?", "options": ["Xung quanh điện tích có điện trường, điện trường truyền tương tác điện.", "Tính chất cơ bản của điện trường là tác dụng lực lên điện tích đặt trong nó.", "Điện trường tĩnh là do các hạt mang điện đứng yên sinh ra.", "Điện trường đều là điện trường có các đường sức song song nhưng không cách đều nhau."], "answer": 3, "explanation": ""}, {"type": "multiple_choice", "question": "Tại một điểm xác định trong điện trường tĩnh, nếu độ lớn của điện tích thử tăng 2 lần thì độ lớn cường độ điện trường sẽ", "options": ["tăng 2 lần.", "giảm 2 lần.", "không đổi.", "giảm 4 lần."], "answer": 2, "explanation": ""}, {"type": "multiple_choice", "question": "Vector cường độ điện trường tại mỗi điểm có chiều", "options": ["cùng chiều với lực điện tác dụng lên điện tích thử dương tại điểm đó.", "cùng chiều với lực điện tác dụng lên điện tích thử tại điểm đó.", "phụ thuộc độ lớn điện tích thử.", "phụ thuộc nhiệt độ của môi trường."], "answer": 0, "explanation": ""}, {"type": "multiple_choice", "question": "Cho một điện tích điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image59_rId10082.png\" alt=\"\" style=\"height:21px\"> điện trường tại một điểm mà nó gây ra có chiều", "options": ["hướng về phía nó.", "hướng ra xa nó.", "phụ thuộc độ lớn của nó.", "phụ thuộc vào điện môi xung quanh."], "answer": 0, "explanation": ""}, {"type": "multiple_choice", "question": "Phát biểu nào sau đây là đúng khi nói về đường sức điện?", "options": ["Các đường sức điện có thể cắt nhau.", "Đường sức điện của điện trường tĩnh là những đường song song cách đều nhau.", "Đường sức điện luôn xuất phát từ điện tích dương và kết thúc tại điện tích âm.", "Đường sức điện là đường mà lực điện tác dụng theo."], "answer": 3, "explanation": ""}, {"type": "multiple_choice", "question": "Quy tắc vẽ các đường sức điện nào sau đây là sai?", "options": ["Tại một điểm bất kì trong điện trường nói chung có thể vẽ được một đường sức đi qua điểm đó.", "Các đường sức nói chung xuất phát từ các điện tích âm, tận cùng tại các điện tích dương.", "Các đường sức không cắt nhau.", "Nơi nào cương độ điện trường lớn hơn thì các đường sức được vẽ dày hơn."], "answer": 1, "explanation": "Theo quy ước chiều đường sức điện thường xuất phát từ điện tích dương và kết thúc ở điện tích âm."}, {"type": "multiple_choice", "question": "Phát biểu nào sau đây là sai về tính chất của đường sức điện trường?", "options": ["Đường sức điện trường là những đường có hướng.", "Nơi nào có điện trường mạnh thì đường sức mau, nơi nào có điện trường yếu thì đường sức thưa.", "Với điện tích dương thì các đường sức có hướng đi ra khỏi điện tích.", "Với mỗi điểm trong điện trường đều có thể có nhiều hơn một đường sức đi qua."], "answer": 3, "explanation": ""}, {"type": "multiple_choice", "question": "Đường sức điện nào ở hình vẽ bên là đường sức của điện trường đều? hình a<img class=\"figure\" src=\"/exams/kttx-dien-truong/media/image10084.png\" alt=\"\"> hình b <img class=\"figure\" src=\"/exams/kttx-dien-truong/media/image10087.png\" alt=\"\"> hình c<img class=\"figure\" src=\"/exams/kttx-dien-truong/media/image10090.png\" alt=\"\">", "options": ["Hình <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image81_rId10093.png\" alt=\"\" style=\"height:14px\">", "Hình <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image82_rId10095.png\" alt=\"\" style=\"height:19px\">", "Hình <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image83_rId10097.png\" alt=\"\" style=\"height:14px\">", "Hình <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image84_rId10099.png\" alt=\"\" style=\"height:21px\">"], "answer": 2, "explanation": ""}, {"type": "multiple_choice", "question": "Hình vẽ bên vẽ một số đường sức của hệ thống hai điện tích điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image85_rId10101.png\" alt=\"\" style=\"height:17px\">và <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image86_rId10103.png\" alt=\"\" style=\"height:19px\"> Phát biểu đúng là <img class=\"figure\" src=\"/exams/kttx-dien-truong/media/image10105.png\" alt=\"\">", "options": ["<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image88_rId10108.png\" alt=\"\" style=\"height:17px\">là điện tích dương, <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image89_rId10110.png\" alt=\"\" style=\"height:17px\">là điện tích âm.", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image90_rId10112.png\" alt=\"\" style=\"height:17px\">là điện tích âm, <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image91_rId10114.png\" alt=\"\" style=\"height:17px\">là điện tích dương.", "Cả <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image92_rId10116.png\" alt=\"\" style=\"height:17px\">và <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image93_rId10118.png\" alt=\"\" style=\"height:17px\">đều là điện tích dương.", "Cả <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image94_rId10120.png\" alt=\"\" style=\"height:17px\">và <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image95_rId10122.png\" alt=\"\" style=\"height:17px\">đều là điện tích âm."], "answer": 3, "explanation": ""}, {"type": "multiple_choice", "question": "Đường sức điện cho biết", "options": ["độ lớn lực tác dụng lên điện tích đặt trên đường sức ấy.", "độ lớn của điện tích nguồn sinh ra điện trường được biểu diễn bằng đường sức ấy.", "độ lớn điện tích thử cần đặt trên đường sức ấy.", "hướng của lực điện tác dụng lên điện tích điểm đặt trên đường sức ấy."], "answer": 3, "explanation": "Đường sức điện cho biết hướng của lực điện tác dụng lên điện tích điểm đặt trên đường sức ấy."}, {"type": "multiple_choice", "question": "Phát biểu nào sau đây không đúng với đặc điểm đường sức điện?", "options": ["Các đường sức của cùng một điện trường có thể cắt nhau.", "Các đường sức của điện trường tĩnh là đường không khép kín.", "Hướng của đường sức điện tại mỗi điểm là hướng của vector cường độ điện trường tại điểm đó.", "Các đường sức là các đường có hướng."], "answer": 0, "explanation": "Nhận xét không đúng khi nói về đặc điểm đường sức điện là các đường sức của cùng một điện trường có thể cắt nhau."}, {"type": "multiple_choice", "question": "Phát biểu nào sau đây là sai khi nói về nguyên lí chồng chất điện trường?", "options": ["Hai điện tích <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image111_rId10124.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image112_rId10126.png\" alt=\"\" style=\"height:24px\"> gây ra tại cùng 1 điểm <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image113_rId10128.png\" alt=\"\" style=\"height:17px\">các điện trường <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image114_rId10130.png\" alt=\"\" style=\"height:27px\"> và <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image115_rId10132.png\" alt=\"\" style=\"height:27px\"> thì vector cường độ điện trường tổng hợp tại điểm đó được tính bằng công thức <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image116_rId10134.png\" alt=\"\" style=\"height:27px\">", "Độ lớn của cường độ điện trường tổng hợp tại <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image117_rId10136.png\" alt=\"\" style=\"height:17px\">bằng tổng các độ lớn của các cường độ điện trường thành phần E = E~1~ + E~2~.", "Nguyên lí chồng chất điện trường cho biết vector cường độ điện trường tổng hợp phải tính theo quy tắc cộng vector hình bình hành.", "Điều đó có thể mở rộng cho trường hợp nhiều điện tích điểm hơn hoặc cho một hệ điện tích phân bố liên tục."], "answer": 1, "explanation": ""}, {"type": "multiple_choice", "question": "Cường độ điện trường do điện tích dương <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image118_rId10138.png\" alt=\"\" style=\"height:21px\"> đặt tại <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image119_rId10140.png\" alt=\"\" style=\"height:17px\"> gây ra tại <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image120_rId10142.png\" alt=\"\" style=\"height:17px\"> cách <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image121_rId10144.png\" alt=\"\" style=\"height:24px\"> khoảng r có", "options": ["điểm đặt tại <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image122_rId10146.png\" alt=\"\" style=\"height:21px\"> chiều hướng vào <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image123_rId10148.png\" alt=\"\" style=\"height:21px\"> độ lớn <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image124_rId10150.png\" alt=\"\" style=\"height:44px\">", "điểm đặt tại <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image125_rId10152.png\" alt=\"\" style=\"height:21px\"> chiều hướng ra xa <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image126_rId10154.png\" alt=\"\" style=\"height:19px\">", "phương trùng với đường thẳng nối <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image127_rId10156.png\" alt=\"\" style=\"height:21px\">và <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image128_rId10158.png\" alt=\"\" style=\"height:21px\"> độ lớn <img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image129_rId10160.png\" alt=\"\" style=\"height:44px\">", "<img class=\"eq\" src=\"/exams/kttx-dien-truong/media/image130_rId10162.png\" alt=\"\" style=\"height:21px\">đúng."], "answer": 3, "explanation": ""}]$json$::jsonb);

