values ('TNLT 3.1 – Lực tương tác Coulomb giữa hai điện tích', 40, true, $json$[{"type": "multiple_choice", "question": "Biểu thức của định luật Coulomb là", "options": ["<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image1_rId10001.png\" alt=\"\" style=\"height:42px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image2_rId10003.png\" alt=\"\" style=\"height:43px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image3_rId10005.png\" alt=\"\" style=\"height:43px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image4_rId10007.png\" alt=\"\" style=\"height:43px\">"], "answer": 2, "explanation": "Biểu thức của định luật Coulomb <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image5_rId10009.png\" alt=\"\" style=\"height:43px\">"}, {"type": "multiple_choice", "question": "Bốn vật kích thước nhỏ <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image6_rId10011.png\" alt=\"\" style=\"height:21px\"> nhiễm điện. Vật <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image7_rId10013.png\" alt=\"\" style=\"height:16px\"> hút vật <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image8_rId10015.png\" alt=\"\" style=\"height:16px\"> nhưng đẩy vật <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image9_rId10017.png\" alt=\"\" style=\"height:21px\"> vật <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image10_rId10019.png\" alt=\"\" style=\"height:19px\"> hút vật <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image11_rId10021.png\" alt=\"\" style=\"height:19px\"> Biết <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image12_rId10023.png\" alt=\"\" style=\"height:16px\"> nhiễm điện dương. Hỏi <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image13_rId10025.png\" alt=\"\" style=\"height:21px\"> nhiễm điện gì?", "options": ["<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image14_rId10027.png\" alt=\"\" style=\"height:16px\"> âm, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image15_rId10029.png\" alt=\"\" style=\"height:19px\"> âm, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image16_rId10031.png\" alt=\"\" style=\"height:16px\"> dương.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image17_rId10033.png\" alt=\"\" style=\"height:16px\"> âm, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image18_rId10035.png\" alt=\"\" style=\"height:19px\"> dương, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image19_rId10037.png\" alt=\"\" style=\"height:16px\"> dương.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image20_rId10039.png\" alt=\"\" style=\"height:16px\"> âm, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image21_rId10041.png\" alt=\"\" style=\"height:19px\"> dương, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image22_rId10043.png\" alt=\"\" style=\"height:16px\"> âm.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image23_rId10045.png\" alt=\"\" style=\"height:16px\"> dương, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image24_rId10047.png\" alt=\"\" style=\"height:19px\"> âm, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image25_rId10049.png\" alt=\"\" style=\"height:16px\"> dương."], "answer": 2, "explanation": "Vì vật <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image26_rId10051.png\" alt=\"\" style=\"height:16px\"> nhiễm điện dương mà <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image27_rId10053.png\" alt=\"\" style=\"height:16px\"> hút <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image28_rId10055.png\" alt=\"\" style=\"height:16px\"> nên <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image29_rId10057.png\" alt=\"\" style=\"height:16px\"> nhiễm điện âm, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image30_rId10059.png\" alt=\"\" style=\"height:16px\"> đẩy <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image31_rId10061.png\" alt=\"\" style=\"height:19px\"> nên <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image32_rId10063.png\" alt=\"\" style=\"height:19px\"> nhiễm điện dương, C hút <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image33_rId10065.png\" alt=\"\" style=\"height:16px\"> nên <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image34_rId10067.png\" alt=\"\" style=\"height:16px\"> nhiễm điện âm."}, {"type": "multiple_choice", "question": "Dấu của các điện tích <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image35_rId10069.png\" alt=\"\" style=\"height:24px\"> trên hình là <img class=\"figure\" src=\"/exams/tnlt-coulomb/media/image10071.png\" alt=\"\">", "options": ["<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image37_rId10074.png\" alt=\"\" style=\"height:24px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image38_rId10076.png\" alt=\"\" style=\"height:24px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image39_rId10078.png\" alt=\"\" style=\"height:24px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image40_rId10080.png\" alt=\"\" style=\"height:24px\">"], "answer": 3, "explanation": "Theo hình vẽ thì ta thấy hai điện tích trên là cùng dấu nên <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image41_rId10082.png\" alt=\"\" style=\"height:24px\">"}, {"type": "multiple_choice", "question": "Phát biểu nào sau đây không đúng?", "options": ["Điện môi là môi trường cách điện.", "Hằng số điện môi của chân không bằng 1.", "Hằng số điện môi của một môi trường cho biết lực tương tác điện tích trong môi trường đó nhỏ hơn khi chúng đặt trong chân không bao nhiêu lần.", "Hằng số điện môi có thể nhỏ hơn 1."], "answer": 3, "explanation": "Hằng số điện môi luôn lớn hơn hoặc bằng 1, với chân không hằng số điện môi bằng 1."}, {"type": "multiple_choice", "question": "Độ lớn của lực tương tác giữa hai điện tích điểm trong không khí", "options": ["tỉ lệ với bình phương khoảng cách giữa hai điện tích.", "tỉ lệ với khoảng cách giữa hai điện tích.", "tỉ lệ nghịch với bình phương khoảng cách giữa hai điện tích.", "tỉ lệ nghịch với khoảng cách giữa hai điện tích."], "answer": 2, "explanation": "Ta có lực tương tác giữa 2 điện tích điểm trong không khí có độ lớn xác định bởi biểu thức<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image46_rId10084.png\" alt=\"\" style=\"height:43px\">."}, {"type": "multiple_choice", "question": "Hai chất điểm mang điện tích <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image47_rId10086.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image48_rId10088.png\" alt=\"\" style=\"height:24px\"> khi đặt gần nhau chúng đẩy nhau. Kết luận nào sau đây không đúng?", "options": ["<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image49_rId10090.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image50_rId10092.png\" alt=\"\" style=\"height:24px\"> đều là điện tích dương.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image51_rId10094.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image52_rId10096.png\" alt=\"\" style=\"height:24px\"> đều là điện tích âm.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image53_rId10098.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image54_rId10100.png\" alt=\"\" style=\"height:24px\"> trái dấu nhau.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image55_rId10102.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image56_rId10104.png\" alt=\"\" style=\"height:24px\"> cùng dấu nhau."], "answer": 2, "explanation": "Vì hai chất điểm mang điện tích <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image57_rId10106.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image58_rId10108.png\" alt=\"\" style=\"height:24px\"> khi đặt gần nhau chúng đẩy nhau nên hai điện tích cùng dấu nhau, có thể cùng là điện tích dương hoặc cùng là điện tích âm."}, {"type": "multiple_choice", "question": "Khẳng định nào sau đây không đúng? Lực tương tác giữa hai điện tích điểm trong chân không", "options": ["có phương là đường thẳng nối hai điện tích.", "có độ lớn tỉ lệ với tích độ lớn hai điện tích.", "có độ lớn tỉ lệ nghịch với khoảng cách giữa hai điện tích.", "là lực hút khi hai điện tích trái dấu."], "answer": 2, "explanation": "Lực tương tác giữa hai chất điểm trong chân không có Phương là đường thẳng nối hai điện tích. Độ lớn tỉ lệ với tích độ lớn hai điện tích, tỉ lệ nghịch với bình phương khoảng cách giữa hai điện tích. Là lực hút khi hai điện tích trái dấu, lực đẩy khi hai điện tích cùng dấu."}, {"type": "multiple_choice", "question": "Cho 2 điện tích có độ lớn không đổi, đặt cách nhau một khoảng không đổi. Lực tương tác giữa chúng sẽ lớn nhất khi đặt trong", "options": ["chân không.", "nước nguyên chất.", "dầu hỏa.", "không khí ở điều kiện tiêu chuẩn."], "answer": 0, "explanation": "Áp dụng <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image60_rId10110.png\" alt=\"\" style=\"height:43px\"> để <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image61_rId10112.png\" alt=\"\" style=\"height:24px\"> thì <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image62_rId10114.png\" alt=\"\" style=\"height:19px\"> (môi trường chân không)."}, {"type": "multiple_choice", "question": "Hai quả cầu kim loại giống nhau mang điện tích <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image63_rId10116.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image64_rId10118.png\" alt=\"\" style=\"height:24px\"> với <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image65_rId10120.png\" alt=\"\" style=\"height:27px\"> đưa chúng lại gần thì chúng hút nhau. Nếu cho chúng tiếp xúc nhau rồi sau đó tách ra thì mỗi quả cầu sẽ mang điện tích", "options": ["<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image66_rId10122.png\" alt=\"\" style=\"height:24px\">", "0.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image68_rId10124.png\" alt=\"\" style=\"height:24px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image69_rId10126.png\" alt=\"\" style=\"height:42px\">"], "answer": 1, "explanation": "Lúc đầu hai quả cầu hút nhau nên <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image70_rId10128.png\" alt=\"\" style=\"height:24px\"> Theo định luật bảo toàn điện tích, sau khi tiếp xúc và tách ra thì điện tích hai quả cầu <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image71_rId10130.png\" alt=\"\" style=\"height:42px\">"}, {"type": "multiple_choice", "question": "Hai quả cầu kim loại giống nhau mang điện tích lần lượt là <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image72_rId10132.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image73_rId10134.png\" alt=\"\" style=\"height:24px\"> với <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image74_rId10136.png\" alt=\"\" style=\"height:27px\"> khi đưa lại gần thì chúng đẩy nhau. Nếu cho chúng tiếp xúc nhau rồi sau đó tách chúng ra thì mỗi quả cầu mang điện tích", "options": ["<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image75_rId10138.png\" alt=\"\" style=\"height:24px\">", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image76_rId10140.png\" alt=\"\" style=\"height:42px\">", "0.", "<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image78_rId10142.png\" alt=\"\" style=\"height:24px\">"], "answer": 0, "explanation": "Lúc đầu hai quả cầu đẩy nhau nên<img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image79_rId10144.png\" alt=\"\" style=\"height:24px\"> Theo định luật bảo toàn điện tích, sau khi tiếp xúc và tách ra thì điện tích hai quả cầu <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image80_rId10146.png\" alt=\"\" style=\"height:42px\">"}, {"type": "multiple_choice", "question": "Hai điện tích điểm đặt cách nhau một khoảng <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image81_rId10148.png\" alt=\"\" style=\"height:16px\"> dịch chuyển để khoảng cách giữa hai điện tích điểm đó giảm đi hai lần nhưng vẫn giữ nguyên độ lớn điện tích của chúng. Khi đó, lực tương tác giữa hai điện tích", "options": ["tăng lên hai lần.", "giảm đi hai lần.", "tăng lên bốn lần.", "giảm đi bốn lần."], "answer": 2, "explanation": "Ta có <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image82_rId10150.png\" alt=\"\" style=\"height:42px\"> Khi khoảng cách giữa hai điện tích giảm đi hai lần thì lực tương tác tăng lên bốn lần."}, {"type": "multiple_choice", "question": "Hai quả cầu nhẹ cùng khối lượng được treo gần nhau bằng hai dây cách điện có cùng chiều dài và hai quả cầu không chạm nhau. Tích cho hai quả cầu điện tích cùng dấu nhưng có độ lớn khác nhau thì lực tác dụng làm dây treo hai điện tích lệch đi những góc so với phương thẳng đứng", "options": ["bằng nhau.", "quả cầu nào tích điện có độ lớn điện tích lớn hơn thì có góc lệch lớn hơn.", "quả cầu nào tích điện có độ lớn điện tích lớn hơn thì có góc lệch nhỏ hơn.", "quả cầu nào tích điện có độ lớn điện tích nhỏ hơn thì có góc lệch nhỏ hơn."], "answer": 0, "explanation": "Lực tương tác của hai quả cầu lên nhau là bằng nhau vì vậy góc lệch của dây treo so với phương thẳng đứng là như nhau."}, {"type": "multiple_choice", "question": "Khẳng định nào sau đây không đúng khi nói về lực tương tác giữa hai điện tích điểm đặt trong chân không?", "options": ["Có phương là đường thẳng nối hai điện tích.", "Có độ lớn tỉ lệ với tích độ lớn hai điện tích.", "Có độ lớn tỉ lệ nghịch với khoảng cách giữa hai điện tích.", "Là lực hút khi hai điện tích trái dấu."], "answer": 2, "explanation": "Lực tương tác điện là lực hút nếu hai điện tích trái dấu và là lực đẩy nếu hai điện tích cùng dấu. Theo định luật Culong lực tương tác giữa 2 điện tích điểm trong chân không có phương nằm trên đường thẳng nối hai điện tích có độ lớn tỷ lệ thuận với tích độ lớn hai điện tích và tỷ lệ nghịch với bình phương khoảng cách giữa hai điện tích."}, {"type": "multiple_choice", "question": "Có hai quả cầu giống nhau cùng mang điện tích có độ lớn như nhau <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image83_rId10152.png\" alt=\"\" style=\"height:29px\"> khi đưa chúng lại gần thì chúng đẩy nhau. Cho chúng tiếp xúc nhau, sau đó tách chúng ra một khoảng nhỏ thì chúng", "options": ["hút nhau.", "đẩy nhau.", "có thể hút hoặc đẩy nhau.", "không tương tác nhau."], "answer": 1, "explanation": "Do <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image84_rId10154.png\" alt=\"\" style=\"height:24px\"> đẩy <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image85_rId10156.png\" alt=\"\" style=\"height:24px\"> <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image86_rId10158.png\" alt=\"\" style=\"height:24px\"> cùng dấu <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image87_rId10160.png\" alt=\"\" style=\"height:24px\"> Hai điện tích sau khi tiếp xúc <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image88_rId10162.png\" alt=\"\" style=\"height:42px\"> Nên chúng vẫn đẩy nhau."}, {"type": "multiple_choice", "question": "Có hai quả cầu giống nhau mang điện tích <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image89_rId10164.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image90_rId10166.png\" alt=\"\" style=\"height:24px\"> có độ lớn như nhau <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image91_rId10168.png\" alt=\"\" style=\"height:29px\"> khi đưa chúng lại gần nhau thì chúng hút nhau. Cho chúng tiếp xúc nhau rồi tách chúng ra một khoảng thì chúng", "options": ["hút nhau.", "đẩy nhau.", "có thể hút hoặc đẩy nhau.", "không tương tác nhau."], "answer": 3, "explanation": "Hai quả cầu, điện tích có độ lớn bằng nhau, hút nhau chứng tỏ chúng trái dấu. Khi có tiếp xúc điện tích hai quả cầu này trung hòa với nhau nên khi tách chúng ra chúng sẽ không tương tác với nhau nữa."}, {"type": "multiple_choice", "question": "Hai quả cầu kim loại <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image92_rId10170.png\" alt=\"\" style=\"height:16px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image93_rId10172.png\" alt=\"\" style=\"height:16px\"> tích điện tích lần lượt là <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image94_rId10174.png\" alt=\"\" style=\"height:24px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image95_rId10176.png\" alt=\"\" style=\"height:24px\"> trong đó <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image96_rId10178.png\" alt=\"\" style=\"height:24px\"> là điện tích dương, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image97_rId10180.png\" alt=\"\" style=\"height:24px\"> là điện tích âm <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image98_rId10182.png\" alt=\"\" style=\"height:27px\"> Cho 2 quả cầu tiếp xúc nhau, sau đó tách chúng ra và đưa quả cầu <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image100_rId10184.png\" alt=\"\" style=\"height:16px\"> lại gần quả cầu <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image101_rId10186.png\" alt=\"\" style=\"height:19px\"> đang tích điện âm thì chúng", "options": ["hút nhau.", "đẩy nhau.", "không hút cũng không đẩy nhau.", "có thể hút hoặc đẩy nhau."], "answer": 0, "explanation": "Trước khi <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image102_rId10188.png\" alt=\"\" style=\"height:16px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image103_rId10190.png\" alt=\"\" style=\"height:16px\"> tiếp xúc nhau vì <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image104_rId10192.png\" alt=\"\" style=\"height:24px\"> là điện tích dương, <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image105_rId10194.png\" alt=\"\" style=\"height:24px\"> là điện tích âm <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image106_rId10196.png\" alt=\"\" style=\"height:27px\"> nên <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image107_rId10198.png\" alt=\"\" style=\"height:24px\"> Sau khi <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image108_rId10200.png\" alt=\"\" style=\"height:16px\"> và <img class=\"eq\" src=\"/exams/tnlt-coulomb/media/image109_rId10202.png\" alt=\"\" style=\"height:16px\"> tiếp xúc nhau chúng nhiễm điện cùng dấu và mang điện dương. Đưa quả c